import requests
from requests.auth import HTTPBasicAuth

BASE_URL = "http://localhost:8000"

def test_post_api_auth_forgot_password_unknown_user():
    url = f"{BASE_URL}/api/auth/forgot-password"
    unknown_username = "user_does_not_exist_12345"
    headers = {
        "Content-Type": "application/json"
    }
    auth = HTTPBasicAuth("haseeb-heaven", "123456")
    payload = {
        "username": unknown_username
    }
    try:
        response = requests.post(url, json=payload, headers=headers, auth=auth, timeout=30)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"
    assert response.status_code == 404, f"Expected status code 404, got {response.status_code}"
    # Response should indicate user not found
    try:
        json_resp = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"
    # The 404 response content is likely a string message or object, accept any content
    # but verify that it relates to user not found (if message is provided)
    if isinstance(json_resp, dict):
        msg = json_resp.get("detail") or json_resp.get("message") or ""
        assert "not found" in msg.lower() or "user" in msg.lower(), f"Unexpected 404 response content: {json_resp}"

test_post_api_auth_forgot_password_unknown_user()

import requests

BASE_URL = "http://localhost:8000"
TIMEOUT = 30


def test_post_api_auth_reset_password_invalid_token():
    url = f"{BASE_URL}/api/auth/reset-password"
    headers = {
        "Content-Type": "application/json"
    }

    # Test case 1: expired or invalid reset token
    payload_invalid_token = {
        "token": "this_is_an_invalid_or_expired_token",
        "new_password": "ValidPass123!"
    }
    response1 = requests.post(url, json=payload_invalid_token, headers=headers, timeout=TIMEOUT)
    assert response1.status_code == 400, f"Expected 400 for invalid token, got {response1.status_code}"
    try:
        error_response = response1.json()
        assert "token" in str(error_response).lower() or "invalid" in str(error_response).lower() or "expired" in str(error_response).lower()
    except Exception:
        pass  # Response content validation is best effort

    # Test case 2: short new password (too short password)
    payload_short_password = {
        "token": "some_valid_token_but_password_invalid",
        "new_password": "123"  # too short, assuming password policy
    }
    response2 = requests.post(url, json=payload_short_password, headers=headers, timeout=TIMEOUT)
    assert response2.status_code == 400, f"Expected 400 for short password, got {response2.status_code}"
    try:
        error_response = response2.json()
        assert "password" in str(error_response).lower() or "validation" in str(error_response).lower()
    except Exception:
        pass  # Response content validation is best effort


test_post_api_auth_reset_password_invalid_token()

import requests

def test_get_api_profiles_list_owned_profiles():
    base_url = "http://localhost:8000"
    login_url = f"{base_url}/api/auth/login"
    profiles_url = f"{base_url}/api/profiles"

    # Authenticate and get JWT token
    login_data = {
        "username": "haseeb-heaven",
        "password": "123456"
    }

    try:
        login_response = requests.post(login_url, data=login_data, timeout=30)
        login_response.raise_for_status()
    except requests.exceptions.RequestException as e:
        assert False, f"Login request failed: {e}"

    assert login_response.status_code == 200, f"Login unexpected status code: {login_response.status_code}"

    try:
        token_data = login_response.json()
    except ValueError:
        assert False, "Login response is not valid JSON"

    assert "access_token" in token_data, "Login response missing access_token"
    access_token = token_data["access_token"]

    headers = {
        "Accept": "application/json",
        "Authorization": f"Bearer {access_token}"
    }

    try:
        response = requests.get(profiles_url, headers=headers, timeout=30)
        response.raise_for_status()
    except requests.exceptions.RequestException as e:
        assert False, f"Profiles request failed: {e}"

    assert response.status_code == 200, f"Profiles unexpected status code: {response.status_code}"
    try:
        profiles = response.json()
    except ValueError:
        assert False, "Profiles response is not valid JSON"

    assert isinstance(profiles, list), "Response JSON is not a list"
    for profile in profiles:
        assert isinstance(profile, dict), "Profile item is not a dictionary"
        assert "id" in profile, "Profile dictionary missing 'id'"
        assert "full_name" in profile, "Profile dictionary missing 'full_name'"
        # 'email' is optional and may be None, check if present
        assert "email" in profile, "Profile dictionary missing 'email'"


test_get_api_profiles_list_owned_profiles()
